   282→
   283→    match (cr1 || cr2, crlf1 || crlf2, lf1 || lf2) {
   284→        (false, false, false) => false,
   285→        (true, false, false) => false,
   286→        (false, true, false) => false,
   287→        (false, false, true) => false,
   288→        _ => true,
   289→    }
   290→}
