   292→impl<'a> fmt::Display for SimpleDiff<'a> {
   293→    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
   294→        let left = self.left();
   295→        let right = self.right();
   296→        let newlines_matter = newlines_matter(left, right);
